// COUCHE 1 — INGESTION
// Détecte le type d'input et normalise le contenu

const input = $input.first().json.body || $input.first().json;
const userInput = input.content || input.text || input.url || '';

function detectSourceType(content) {
  // URL detection
  if (/^https?:\/\//i.test(content.trim())) {
    // Détection sport/match
    if (/rugby|top14|ligue|match|score|résultat/i.test(content)) {
      return 'url_match';
    }
    return 'url_article';
  }
  // PDF (sera géré séparément)
  if (content.startsWith('%PDF') || input.source_type === 'pdf') {
    return 'communique_pdf';
  }
  // Texte brut par défaut
  return 'texte_brut';
}

function extractMetadata(content, sourceType) {
  const metadata = {
    language: 'fr',
    word_count: content.split(/\s+/).length,
    date: new Date().toISOString()
  };

  if (input.title) metadata.title = input.title;
  if (input.source_url) metadata.source_url = input.source_url;
  if (input.source_name) metadata.source_name = input.source_name;

  return metadata;
}

const sourceType = input.source_type || detectSourceType(userInput);
let rawContent = userInput;

// Si c'est une URL, on flag pour le scraping (prochain node)
const needsScraping = sourceType === 'url_article' || sourceType === 'url_match';

const ingestedContent = {
  source_type: sourceType,
  raw_content: needsScraping ? '' : rawContent,
  metadata: extractMetadata(rawContent, sourceType),
  _needs_scraping: needsScraping,
  _url: needsScraping ? userInput.trim() : null
};

return [{ json: ingestedContent }];

// Nettoie le HTML scrappé et extrait le contenu textuel
const html = $input.first().json.data || $input.first().json.body || '';

// Suppression des tags script, style, nav, header, footer
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

// Extraction du titre depuis le HTML original
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const h1Match = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
const title = h1Match ? h1Match[1].trim() : (titleMatch ? titleMatch[1].trim() : '');

// Limiter à 5000 mots pour ne pas exploser les tokens
const words = text.split(/\s+/);
if (words.length > 5000) {
  text = words.slice(0, 5000).join(' ') + '\n[contenu tronqué]';
}

return [{ json: {
  source_type: 'url_article',
  raw_content: text,
  metadata: {
    title: title,
    source_url: $('Couche 1 — Ingestion').first().json._url,
    language: 'fr',
    word_count: words.length,
    date: new Date().toISOString()
  }
}}];

