// Parse le JSON du routeur éditorial et prépare l'input pour la Couche 3
const routerOutput = $input.first().json;
let editorialPlan;

try {
  // Le LLM peut renvoyer du JSON dans un bloc markdown
  let text = routerOutput.text || routerOutput.message || JSON.stringify(routerOutput);
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  editorialPlan = JSON.parse(text);
} catch (e) {
  throw new Error('Le routeur éditorial n\'a pas renvoyé du JSON valide: ' + e.message);
}

// Récupère le contenu ingéré
const ingested = $('Merge Contenu').first().json;

return [{ json: {
  editorial_plan: editorialPlan,
  raw_content: ingested.raw_content,
  metadata: ingested.metadata
}}];

