// Assemble le kit final
const generatorOutput = $input.first().json;
const editorialData = $('Parse Editorial Plan').first().json;

let assets;
try {
  let text = generatorOutput.text || generatorOutput.message || JSON.stringify(generatorOutput);
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(text);
  assets = parsed.assets || parsed;
} catch (e) {
  throw new Error('Le générateur n\'a pas renvoyé du JSON valide: ' + e.message);
}

const kit = {
  editorial_plan: editorialData.editorial_plan,
  assets: assets,
  metadata: editorialData.metadata,
  generated_at: new Date().toISOString(),
  generation_time_ms: 0 // TODO: mesurer le temps réel
};

return [{ json: kit }];
